    "triggerBinding": "每个计划必须绑定具体触发器（时间/事件/条件）",
    "contextHandoff": "session 启动必读：heartbeat-state.json → 主动性反馈.md → 训练日志",
    "instantReward": "执行后立即记录到反馈文件，给自己肯定",
    "failureAnalysis": "下次训练分析失败原因，调整机制不责备"
  }
}

